+import { lerpColor, drawPolygon } from '../utils/graphics';
+
+const BRICK_WIDTH = 40;
+const BRICK_HEIGHT = 20;
+const MORTAR_COLOR = '#b0a9a0';
+
+function randomBrickColor(baseColor) {
+  // Slightly vary the base color per brick
+  const variation = () => Math.floor((Math.random() - 0.5) * 20);
+  const c = baseColor.match(/\d+/g).map(Number);
+  const r = Math.min(255, Math.max(0, c[0] + variation()));
+  const g = Math.min(255, Math.max(0, c[1] + variation()));
+  const b = Math.min(255, Math.max(0, c[2] + variation()));
+  return `rgb(${r},${g},${b})`;
+}
+
+function drawBrick(ctx, x, y, width, height, baseColor) {
+  // Draw brick with 3D shading (top highlight, bottom shadow)
+  const color = randomBrickColor(baseColor);
+  // Brick base
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, width, height);
+
+  // Top highlight gradient
+  const topGradient = ctx.createLinearGradient(x, y, x, y + height / 3);
+  topGradient.addColorStop(0, 'rgba(255,255,255,0.4)');
+  topGradient.addColorStop(1, 'rgba(255,255,255,0)');
+  ctx.fillStyle = topGradient;
+  ctx.fillRect(x, y, width, height / 3);
+
+  // Bottom shadow gradient
+  const bottomGradient = ctx.createLinearGradient(x, y + height * 2 / 3, x, y + height);
+  bottomGradient.addColorStop(0, 'rgba(0,0,0,0)');
+  bottomGradient.addColorStop(1, 'rgba(0,0,0,0.3)');
+  ctx.fillStyle = bottomGradient;
+  ctx.fillRect(x, y + height * 2 / 3, width, height / 3);
+
+  // Mortar lines (top and left edges)
+  ctx.strokeStyle = MORTAR_COLOR;
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(x, y);
+  ctx.lineTo(x + width, y);
+  ctx.lineTo(x + width, y + height);
+  ctx.stroke();
+}
+
+export function renderStoneWall(ctx, x, y, width, height) {
+  // 3/4 top-down perspective: bricks are trapezoids
+  const baseColor = 'rgb(130,110,90)';
+  const rows = Math.ceil(height / BRICK_HEIGHT);
+  const cols = Math.ceil(width / BRICK_WIDTH);
+
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      const offsetX = (row % 2) * (BRICK_WIDTH / 2);
+      const brickX = x + col * BRICK_WIDTH - offsetX;
+      const brickY = y + row * BRICK_HEIGHT;
+
+      // Draw trapezoid brick for 3/4 perspective
+      const topWidth = BRICK_WIDTH * 0.9;
+      const bottomWidth = BRICK_WIDTH;
+      const heightBrick = BRICK_HEIGHT;
+
+      // Calculate points for trapezoid
+      const points = [
+        { x: brickX + (BRICK_WIDTH - topWidth) / 2, y: brickY },
+        { x: brickX + (BRICK_WIDTH + topWidth) / 2, y: brickY },
+        { x: brickX + bottomWidth, y: brickY + heightBrick },
+        { x: brickX, y: brickY + heightBrick },
+      ];
+
+      // Draw mortar background
+      ctx.fillStyle = MORTAR_COLOR;
+      ctx.beginPath();
+      points.forEach((p, i) => (i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y)));
+      ctx.closePath();
+      ctx.fill();
+
+      // Draw brick with shading
+      // Create clipping path for brick shape
+      ctx.save();
+      ctx.beginPath();
+      points.forEach((p, i) => (i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y)));
+      ctx.closePath();
+      ctx.clip();
+
+      // Fill brick base with color variation
+      const color = randomBrickColor(baseColor);
+      ctx.fillStyle = color;
+      ctx.fillRect(brickX, brickY, BRICK_WIDTH, BRICK_HEIGHT);
+
+      // Top highlight gradient
+      const topGradient = ctx.createLinearGradient(brickX, brickY, brickX, brickY + heightBrick / 3);
+      topGradient.addColorStop(0, 'rgba(255,255,255,0.4)');
+      topGradient.addColorStop(1, 'rgba(255,255,255,0)');
+      ctx.fillStyle = topGradient;
+      ctx.fillRect(brickX, brickY, BRICK_WIDTH, heightBrick / 3);
+
+      // Bottom shadow gradient
+      const bottomGradient = ctx.createLinearGradient(brickX, brickY + heightBrick * 2 / 3, brickX, brickY + heightBrick);
+      bottomGradient.addColorStop(0, 'rgba(0,0,0,0)');
+      bottomGradient.addColorStop(1, 'rgba(0,0,0,0.3)');
+      ctx.fillStyle = bottomGradient;
+      ctx.fillRect(brickX, brickY + heightBrick * 2 / 3, BRICK_WIDTH, heightBrick / 3);
+
+      ctx.restore();
+    }
+  }
+}
+
+// Integration points for wall decorations
+export function getTorchBracketPositions(x, y, width, height) {
+  // Return array of positions along wall top edge for torch brackets
+  const positions = [];
+  const spacing = BRICK_WIDTH * 2;
+  for (let px = x + spacing / 2; px < x + width; px += spacing) {
+    positions.push({ x: px, y: y });
+  }
+  return positions;
+}
+
+export function getTapestryHookPositions(x, y, width, height) {
+  // Return array of positions along wall at 1/3 and 2/3 height for tapestry hooks
+  return [
+    { x: x + width / 3, y: y + height / 3 },
+    { x: x + (2 * width) / 3, y: y + height / 3 },
+    { x: x + width / 3, y: y + (2 * height) / 3 },
+    { x: x + (2 * width) / 3, y: y + (2 * height) / 3 },
+  ];
+}
